public static long skip(InputStream input, long numToSkip) throws IOException {
    long remaining = numToSkip;
    while (remaining > 0) {
        long skipped = input.skip(remaining);
        if (skipped == 0) {
            // Skip returned 0, potentially due to EOF or stream characteristics
            // Try reading a single byte to detect EOF
            int read = input.read();
            if (read == -1) {
                // End of stream reached
                break;
            } else {
                // Byte was read, count it as skipped
                skipped = 1;
            }
        }
        remaining -= skipped;
    }

    return numToSkip - remaining;
}

public static long skip(InputStream input, long numToSkip) throws IOException {
    if (numToSkip <= 0) {
        return 0;
