    long remaining = numToSkip;
    while (remaining > 0) {
        long skipped = input.skip(remaining);
        if (skipped <= 0) {
            // Use read() to work around problems with skip() in certain implementations
            int bytesRead = input.read();
            if (bytesRead < 0) {
                break; // EOF
